from dataclasses import dataclass, field
from enum import StrEnum
import ldap3  # pip install ldap3
import os

class Role(StrEnum):
    VIEWER = 'viewer'    # read-only tools
    ANALYST = 'analyst'  # read + aggregate tools
    EDITOR = 'editor'    # read + write tools (with approval)
    ADMIN = 'admin'      # all tools, no approval gate

ROLE_TOOLS: dict[Role, set[str]] = {
    Role.VIEWER:  {'query_warehouse', 'get_ticket', 'list_orders'},
    Role.ANALYST: {'query_warehouse', 'get_ticket', 'list_orders', 'run_report'},
    Role.EDITOR:  {'query_warehouse', 'get_ticket', 'list_orders', 'run_report',
                   'create_ticket', 'update_ticket', 'post_kafka_event'},
    Role.ADMIN:   None,  # None means unrestricted
}

@dataclass
class IdentityContext:
    username: str
    email: str
    roles: list[Role] = field(default_factory=list)
    groups: list[str] = field(default_factory=list)

def resolve_role(groups: list[str]) -> Role:
    if 'ai-admins' in groups:
        return Role.ADMIN
    if 'ai-editors' in groups:
        return Role.EDITOR
    if 'ai-analysts' in groups:
        return Role.ANALYST
    return Role.VIEWER

def fetch_identity_from_ad(username: str) -> IdentityContext:
    server = ldap3.Server(os.environ['LDAP_HOST'], get_info=ldap3.ALL)
    conn = ldap3.Connection(
        server,
        user=os.environ['LDAP_BIND_DN'],
        password=os.environ['LDAP_BIND_PASS'],
        auto_bind=True,
    )
    base = os.environ['LDAP_BASE_DN']
    conn.search(
        search_base=base,
        search_filter=f'(sAMAccountName={username})',
        attributes=['mail', 'memberOf'],
    )
    if not conn.entries:
        raise PermissionError(f'User {username!r} not found in Active Directory')
    entry = conn.entries[0]
    groups = [
        cn.split(',')[0].replace('CN=', '')
        for cn in (entry.memberOf.values or [])
    ]
    role = resolve_role(groups)
    return IdentityContext(
        username=username,
        email=str(entry.mail),
        roles=[role],
        groups=groups,
    )

def check_permission(identity: IdentityContext, tool_name: str) -> None:
    for role in identity.roles:
        allowed = ROLE_TOOLS.get(role)
        if allowed is None or tool_name in allowed:
            return
    raise PermissionError(
        f'User {identity.username!r} (role {identity.roles}) is not permitted to use tool {tool_name!r}'
    )

