import os, json, requests
from anthropic import Anthropic

SN_BASE = os.environ['SN_INSTANCE']  # e.g. 'https://myco.service-now.com'
SN_AUTH = (os.environ['SN_USER'], os.environ['SN_PASS'])
client = Anthropic()

def sn_get(table: str, params: dict) -> list[dict]:
    resp = requests.get(
        f'{SN_BASE}/api/now/table/{table}',
        auth=SN_AUTH,
        headers={'Accept': 'application/json'},
        params={'sysparm_limit': 10, **params},
        timeout=15,
    )
    resp.raise_for_status()
    return resp.json().get('result', [])

def sn_create(table: str, data: dict) -> dict:
    resp = requests.post(
        f'{SN_BASE}/api/now/table/{table}',
        auth=SN_AUTH,
        json=data,
        headers={'Content-Type': 'application/json'},
        timeout=15,
    )
    resp.raise_for_status()
    return resp.json()['result']

TOOLS = [
    {
        'name': 'search_incidents',
        'description': 'Search ServiceNow incidents by keywords.',
        'input_schema': {
            'type': 'object',
            'properties': {'keywords': {'type': 'string'}},
            'required': ['keywords'],
        },
    },
    {
        'name': 'get_incident',
        'description': 'Get full details of a ServiceNow incident by its number.',
        'input_schema': {
            'type': 'object',
            'properties': {'number': {'type': 'string', 'description': 'e.g. INC0012345'}},
            'required': ['number'],
        },
    },
    {
        'name': 'create_incident',
        'description': 'Create a new ServiceNow incident. Requires human approval.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'short_description': {'type': 'string'},
                'description': {'type': 'string'},
                'urgency': {'type': 'integer', 'description': '1=Critical 2=High 3=Medium 4=Low'},
            },
            'required': ['short_description', 'urgency'],
        },
    },
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == 'search_incidents':
        records = sn_get('incident', {
            'sysparm_query': f"short_descriptionLIKE{inputs['keywords']}^ORdescriptionLIKE{inputs['keywords']}",
            'sysparm_fields': 'number,short_description,state,urgency,assigned_to,sys_updated_on',
        })
        return json.dumps(records)
    if name == 'get_incident':
        records = sn_get('incident', {'sysparm_query': f"number={inputs['number']}"})
        return json.dumps(records[0] if records else {})
    if name == 'create_incident':
        # Wrap in approval gate before executing in production
        result = sn_create('incident', {
            'short_description': inputs['short_description'],
            'description': inputs.get('description', ''),
            'urgency': str(inputs['urgency']),
        })
        return json.dumps({'number': result['number'], 'sys_id': result['sys_id']})
    return 'Unknown tool'

def itsm_agent(user_query: str) -> str:
    messages = [{'role': 'user', 'content': user_query}]
    while True:
        response = client.messages.create(
            model='claude-haiku-4-5-20251001',
            max_tokens=600,
            tools=TOOLS,
            system='You are an IT service management assistant. Use tools to look up and manage incidents.',
            messages=messages,
        )
        if response.stop_reason == 'end_turn':
            return next((b.text for b in response.content if b.type == 'text'), '')
        if response.stop_reason == 'tool_use':
            results = []
            for block in response.content:
                if block.type == 'tool_use':
                    out = execute_tool(block.name, block.input)
                    results.append({'type': 'tool_result', 'tool_use_id': block.id, 'content': out})
            messages.append({'role': 'assistant', 'content': response.content})
            messages.append({'role': 'user', 'content': results})
        else:
            break
    return ''

