import os, json
import snowflake.connector
from anthropic import Anthropic

client = Anthropic()

def snowflake_query(sql: str, params: tuple = ()) -> list[dict]:
    conn = snowflake.connector.connect(
        user=os.environ['SF_USER'],
        password=os.environ['SF_PASSWORD'],
        account=os.environ['SF_ACCOUNT'],
        database=os.environ.get('SF_DATABASE', 'ANALYTICS'),
        schema=os.environ.get('SF_SCHEMA', 'PUBLIC'),
        warehouse=os.environ.get('SF_WAREHOUSE', 'COMPUTE_WH'),
    )
    try:
        cursor = conn.cursor()
        cursor.execute(sql, params)
        columns = [col[0] for col in cursor.description]
        return [dict(zip(columns, row)) for row in cursor.fetchmany(50)]
    finally:
        conn.close()

ALLOWED_TABLES = {'sales_summary', 'customer_cohorts', 'product_revenue', 'churn_risk_scores'}

def safe_query_warehouse(table: str, filters: dict, columns: list[str] | None = None) -> str:
    if table not in ALLOWED_TABLES:
        return json.dumps({'error': f'Table {table!r} is not in the approved list'})
    select_cols = ', '.join(columns) if columns else '*'
    where_parts = []
    values: list = []
    for col, val in filters.items():
        where_parts.append(f'{col} = %s')
        values.append(val)
    where_clause = 'WHERE ' + ' AND '.join(where_parts) if where_parts else ''
    sql = f'SELECT {select_cols} FROM {table} {where_clause} LIMIT 50'
    rows = snowflake_query(sql, tuple(values))
    return json.dumps(rows, default=str)

