import os, json, requests
from requests.auth import HTTPBasicAuth

SAP_BASE = os.environ['SAP_ODATA_URL']  # e.g. https://sap.example.com/sap/opu/odata/sap/ZMY_API/
SAP_AUTH = HTTPBasicAuth(os.environ['SAP_USER'], os.environ['SAP_PASS'])

def sap_get(entity: str, params: dict | None = None) -> list[dict]:
    resp = requests.get(
        f'{SAP_BASE}{entity}',
        auth=SAP_AUTH,
        headers={'Accept': 'application/json'},
        params={'$format': 'json', **(params or {})},
        verify=os.environ.get('SAP_CA_BUNDLE', True),
        timeout=20,
    )
    resp.raise_for_status()
    return resp.json().get('d', {}).get('results', [])

def get_sales_order(order_id: str) -> dict:
    results = sap_get('SalesOrderSet', {'$filter': f"SalesOrderID eq '{order_id}'"})
    return results[0] if results else {}

def get_material_stock(material_id: str, plant: str) -> list[dict]:
    return sap_get(
        'StockOverviewSet',
        {'$filter': f"MaterialNumber eq '{material_id}' and Plant eq '{plant}'"},
    )

def get_open_purchase_orders(vendor_id: str) -> list[dict]:
    return sap_get(
        'PurchaseOrderSet',
        {'$filter': f"VendorID eq '{vendor_id}' and Status eq 'Open'", '$top': '20'},
    )

